import React from 'react';
import { Link } from 'react-router-dom';
import { 
  FaFacebookF, FaTwitter, FaInstagram, FaLinkedinIn, FaYoutube,
  FaHeart, FaEnvelope, FaPhone, FaMapMarkerAlt,
  FaArrowRight, FaGraduationCap, FaUsers, 
  FaRocket, FaGlobe, FaShieldAlt, FaHistory
} from 'react-icons/fa';

const Footer = () => {
  const styles = {
    footer: {
      background: 'linear-gradient(145deg, #0A1929 0%, #0F2B4A 50%, #1A3B5C 100%)',
      color: 'white',
      padding: '4rem 2rem 1rem',
      marginTop: '4rem',
      position: 'relative',
      overflow: 'hidden',
      borderTop: '4px solid #3B82F6'
    },
    container: {
      maxWidth: '1200px',
      margin: '0 auto',
      display: 'grid',
      gridTemplateColumns: 'repeat(3, 1fr)',
      gap: '3rem',
      position: 'relative',
      zIndex: 1
    },
    section: {
      marginBottom: '1.5rem'
    },
    title: {
      color: '#3B82F6',
      marginBottom: '1.5rem',
      fontSize: '1.2rem',
      fontWeight: '700',
      borderBottom: '2px solid rgba(59, 130, 246, 0.3)',
      paddingBottom: '0.5rem',
      display: 'inline-block'
    },
    link: {
      color: '#94A3B8',
      textDecoration: 'none',
      display: 'flex',
      alignItems: 'center',
      gap: '0.8rem',
      marginBottom: '0.8rem',
      transition: 'all 0.3s ease',
      fontSize: '0.95rem',
      '&:hover': {
        color: '#3B82F6',
        transform: 'translateX(5px)'
      }
    },
    icon: {
      fontSize: '0.9rem',
      color: '#3B82F6'
    },
    contactItem: {
      display: 'flex',
      alignItems: 'center',
      gap: '1rem',
      marginBottom: '1rem',
      color: '#94A3B8',
      fontSize: '0.95rem'
    },
    socialLinks: {
      display: 'flex',
      gap: '1rem',
      marginTop: '1.5rem'
    },
    socialIcon: {
      width: '38px',
      height: '38px',
      borderRadius: '50%',
      background: 'rgba(255, 255, 255, 0.05)',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      color: '#3B82F6',
      fontSize: '1.1rem',
      transition: 'all 0.3s ease',
      cursor: 'pointer',
      border: '1px solid rgba(59, 130, 246, 0.2)',
      '&:hover': {
        background: '#3B82F6',
        color: 'white',
        transform: 'translateY(-3px)'
      }
    },
    bottom: {
      textAlign: 'center',
      paddingTop: '2rem',
      marginTop: '3rem',
      borderTop: '1px solid rgba(59, 130, 246, 0.2)',
      color: '#94A3B8'
    },
    heart: {
      color: '#EF4444',
      animation: 'heartbeat 1.5s ease-in-out infinite',
      display: 'inline-block',
      margin: '0 0.3rem'
    },
    stats: {
      display: 'grid',
      gridTemplateColumns: 'repeat(2, 1fr)',
      gap: '1rem',
      marginTop: '1rem'
    },
    statBox: {
      background: 'rgba(59, 130, 246, 0.1)',
      padding: '0.8rem',
      borderRadius: '8px',
      textAlign: 'center'
    }
  };

  const features = [
    { icon: <FaRocket />, text: '1000+ Notes' },
    { icon: <FaHistory />, text: '500+ PYQs' },
    { icon: <FaGlobe />, text: '50+ Courses' },
    { icon: <FaUsers />, text: '10k+ Students' }
  ];

  return (
    <footer style={styles.footer}>
      <div style={styles.container}>
        {/* Column 1: About */}
        <div style={styles.section}>
          <h3 style={styles.title}>
            <FaGraduationCap style={{ marginRight: '0.5rem' }} /> Study Portal
          </h3>
          <p style={{ color: '#94A3B8', lineHeight: '1.6', marginBottom: '1rem', fontSize: '0.9rem' }}>
            Your one-stop destination for quality study materials.
          </p>
          
          <div style={styles.stats}>
            {features.map((feature, index) => (
              <div key={index} style={styles.statBox}>
                <div style={{ color: '#3B82F6', fontSize: '1.1rem' }}>{feature.icon}</div>
                <div style={{ fontSize: '0.8rem', color: '#94A3B8' }}>{feature.text}</div>
              </div>
            ))}
          </div>
        </div>

        {/* Column 2: Quick Links */}
        <div style={styles.section}>
          <h3 style={styles.title}>Quick Links</h3>
          <Link to="/" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Home
          </Link>
          <Link to="/courses" style={styles.link}>
            <FaArrowRight style={styles.icon} /> All Courses
          </Link>
          <Link to="/about" style={styles.link}>
            <FaArrowRight style={styles.icon} /> About Us
          </Link>
          <Link to="/upload" style={styles.link}>
            <FaArrowRight style={styles.icon} /> Upload
          </Link>
        </div>

        {/* Column 3: Contact */}
        <div style={styles.section}>
          <h3 style={styles.title}>Get in Touch</h3>
          
          <div style={styles.contactItem}>
            <FaEnvelope style={{ color: '#3B82F6' }} />
            <span>studyportal@edu.in</span>
          </div>

          <div style={styles.contactItem}>
            <FaPhone style={{ color: '#3B82F6' }} />
            <span>1800-123-4567</span>
          </div>

          <div style={styles.contactItem}>
            <FaMapMarkerAlt style={{ color: '#3B82F6' }} />
            <span>Delhi, India</span>
          </div>

          <div style={styles.socialLinks}>
            <a href="#" style={styles.socialIcon}><FaFacebookF /></a>
            <a href="#" style={styles.socialIcon}><FaTwitter /></a>
            <a href="#" style={styles.socialIcon}><FaInstagram /></a>
            <a href="#" style={styles.socialIcon}><FaLinkedinIn /></a>
            <a href="#" style={styles.socialIcon}><FaYoutube /></a>
          </div>
        </div>
      </div>

      {/* Bottom Bar */}
      <div style={styles.bottom}>
        <p>
          © 2024 Study Portal. Made with <span style={styles.heart}>❤️</span> for education
        </p>
      </div>

      <style>
        {`
          @keyframes heartbeat {
            0%, 100% { transform: scale(1); }
            50% { transform: scale(1.1); }
          }
          a:hover { transition: all 0.3s ease; }
        `}
      </style>
    </footer>
  );
};

export default Footer;
